import{_ as a,c as n,a3 as e,o as t}from"./chunks/framework.BDUoXecB.js";const u=JSON.parse('{"title":"コミットメッセージ規約","description":"","frontmatter":{"sidebarDepth":4,"title":"コミットメッセージ規約","author":"フューチャー株式会社"},"headers":[],"relativePath":"documents/forGitBranch/commit_message_rule.md","filePath":"documents/forGitBranch/commit_message_rule.md"}'),p={name:"documents/forGitBranch/commit_message_rule.md"};function i(l,s,r,c,d,o){return t(),n("div",null,s[0]||(s[0]=[e(`<h2 id="コミットメッセージ規約" tabindex="-1">コミットメッセージ規約 <a class="header-anchor" href="#コミットメッセージ規約" aria-label="Permalink to &quot;コミットメッセージ規約&quot;">​</a></h2><p>Gitのコミットメッセージにの書式についてルール化することで、コミットの目的がわかりやすくなる、履歴からのトラッキングの容易になる利点がある。</p><p>本規約のコミットメッセージの書式としては、<code>Conventional Commits</code>をベースとした規約としている。</p><p>以下の形式でコミットメッセージを記載することとする。</p><div class="language-md vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">md</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;type&gt;: &lt;subject&gt; &lt;gitmoji&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>コミットメッセージは type、subject、gitmojiの最大3つの要素から構成され、それぞれは後述する書式に従うものとする。 この中でも、type、subjectについては必須とし、ほかの要素についてはプロジェクトの運用にしたがい任意とする。</p><h3 id="type" tabindex="-1">type <a class="header-anchor" href="#type" aria-label="Permalink to &quot;type&quot;">​</a></h3><p>typeについては必須の要素となり、以下のいずれかを選択するものとする。</p><table tabindex="0"><thead><tr><th>type</th><th>説明</th></tr></thead><tbody><tr><td><code>feat</code></td><td>新機能の追加</td></tr><tr><td><code>fix</code></td><td>バグの修正</td></tr><tr><td><code>docs</code></td><td>ドキュメンテーションの更新</td></tr><tr><td><code>refactor</code></td><td>リファクタリング</td></tr></tbody></table><h3 id="subject" tabindex="-1">subject <a class="header-anchor" href="#subject" aria-label="Permalink to &quot;subject&quot;">​</a></h3><p>subjectについては必須の要素となり、変更内容を簡潔に記載するものとする。 issue idについては、PRから参照する運用を想定し、コミットメッセージの必須要素とはしないこととする。</p><h3 id="gitmoji" tabindex="-1">gitmoji <a class="header-anchor" href="#gitmoji" aria-label="Permalink to &quot;gitmoji&quot;">​</a></h3><p>gitmojiについては任意の要素となり、変更内容を視認しやすい絵文字の使用を可能とする。</p><p>変更内容と選択される絵文字の対応については厳密とせず、開発者が任意に選択するものとする。</p><p>type(feat, fix, docs, refactorなど)に基づく、選択例を以下に示す。</p><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span> ==== Emojis ====</span></span>
<span class="line"><span> :ambulance:  🚑致命的なバグ修正(fix)</span></span>
<span class="line"><span> :bug:  🐛バグ修正(fix)</span></span>
<span class="line"><span> :+1: 👍機能改善・機能修正(fix)</span></span>
<span class="line"><span> :cop: 👮セキュリティ関連の修正(fix)</span></span>
<span class="line"><span> :art: 🎨レイアウト関連の修正(fix)</span></span>
<span class="line"><span> :green_heart: 💚テストやCIの修正・改善(fix)</span></span>
<span class="line"><span> :wrench: 🔧設定ファイルの修正(fix)</span></span>
<span class="line"><span> :building_construction: 🏗️アーキテクチャの変更(fix)</span></span>
<span class="line"><span> :tada: 🎉大きな機能追加(feat)</span></span>
<span class="line"><span> :sparkles: ✨部分的な機能追加(feat)</span></span>
<span class="line"><span> :up:   🆙依存パッケージ等のアップデート(feat)</span></span>
<span class="line"><span> :memo: 📝ドキュメント修正(docs)</span></span>
<span class="line"><span> :bulb: 💡ソースコードへのコメント追加や修正(docs)</span></span>
<span class="line"><span> :lipstick: 💄Lintエラーの修正やコードスタイルの修正(refactor)</span></span>
<span class="line"><span> :recycle: ♻️リファクタリング(refactor)</span></span>
<span class="line"><span> :fire: 🔥コードやファイルの削除(refactor)</span></span>
<span class="line"><span> :rocket: 🚀パフォーマンス改善(refactor)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br></div></div><h3 id="コミットメッセージ例" tabindex="-1">コミットメッセージ例 <a class="header-anchor" href="#コミットメッセージ例" aria-label="Permalink to &quot;コミットメッセージ例&quot;">​</a></h3><p>上記のルールに従った、コミットメッセージのサンプルは以下のようなものとなる。 以下のようなコミットをルールとすることで、変更内容を視覚的に把握しやすくなる利点がある。</p><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>feat: カレンダー機能の追加 🎉</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fix: メモリリークの修正 🚑</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>docs: デプロイフローをドキュメント化 📝</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>refactor: Lintエラーの修正 💄</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div>`,22)]))}const m=a(p,[["render",i]]);export{u as __pageData,m as default};
